class TreeNode { constructor(v) { this.val=v; this.left=this.right=null; } }
class BST {
  constructor() { this.root=null; }
  insert(v) { this.root=this._ins(this.root,v); }
  _ins(n,v) { if(!n) return new TreeNode(v); if(v<n.val) n.left=this._ins(n.left,v); else if(v>n.val) n.right=this._ins(n.right,v); return n; }
  remove(v) { this.root=this._rem(this.root,v); }
  _rem(n,v) {
    if(!n) return null;
    if(v<n.val) n.left=this._rem(n.left,v);
    else if(v>n.val) n.right=this._rem(n.right,v);
    else {
      if(!n.left) return n.right;
      if(!n.right) return n.left;
      let m=n.right; while(m.left) m=m.left; // in-order successor
      n.val=m.val; n.right=this._rem(n.right,m.val);
    }
    return n;
  }
  search(v) { let n=this.root; while(n) { if(v<n.val) n=n.left; else if(v>n.val) n=n.right; else return true; } return false; }
}
